import 'dart:convert';
import 'package:flutter/material.dart';

class PerfilInterfaz extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    // Base64 image from perfil_falso.txt
    const String base64Image = "";

    return Scaffold(
      backgroundColor: Colors.white,
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.start,
          children: [
            SizedBox(height: 50), // Espaciado inicial
            Text(
              'Hola!',
              style: TextStyle(fontSize: 24, fontWeight: FontWeight.bold),
            ),
            SizedBox(height: 20),
            CircleAvatar(
              radius: 50,
              backgroundImage: MemoryImage(base64Decode(base64Image)),
            ),
            SizedBox(height: 20),
            Text(
              'Elena',
              style: TextStyle(fontSize: 22, fontWeight: FontWeight.bold),
            ),
            Text(
              'Prizzante 2',
              style: TextStyle(fontSize: 16, color: Colors.grey),
            ),
            SizedBox(height: 30),
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 16.0),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  _buildSettingOption(
                    context,
                    icon: Icons.notifications,
                    title: 'Notificaciones',
                    trailing: Switch(value: true, onChanged: (value) {}),
                  ),
                  _buildSettingOption(
                    context,
                    icon: Icons.security,
                    title: 'Seguridad',
                  ),
                  _buildSettingOption(
                    context,
                    icon: Icons.help_outline,
                    title: 'Ayuda',
                  ),
                  _buildSettingOption(
                    context,
                    icon: Icons.logout,
                    title: 'Cerrar sesión',
                    titleColor: Colors.red,
                  ),
                ],
              ),
            )
          ],
        ),
      ),
    );
  }

  Widget _buildSettingOption(BuildContext context,
      {required IconData icon,
        required String title,
        Widget? trailing,
        Color? titleColor}) {
    return ListTile(
      leading: Icon(icon, color: Color(0xFF95B3FF)),
      title: Text(
        title,
        style: TextStyle(color: titleColor ?? Colors.black, fontSize: 16),
      ),
      trailing: trailing ?? Icon(Icons.arrow_forward_ios, size: 16),
      onTap: () {},
    );
  }
}

void main() {
  runApp(MaterialApp(
    home: PerfilInterfaz(),
  ));
}
